#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MAX_LINE 1024
#define MAX_ELEM 256

// trim leading and trailing spaces in place
static void trim(char *s) {
    // leading
    while (*s == ' ') s++;
    memmove(s - (s - (char *)s), s, strlen(s) + 1); // shift to original pointer start
    // trailing
    char *end = s + strlen(s) - 1;
    while (end >= s && *end == ' ') {
        *end = '\0';
        end--;
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char line[MAX_LINE];
        char search[MAX_ELEM];
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0';
        if (!fgets(search, sizeof(search), stdin)) break;
        search[strcspn(search, "\n")] = '\0';
        // trim search
        char *p = search;
        while (*p == ' ') p++;
        memmove(search, p, strlen(p) + 1);
        // trailing spaces of search
        char *end = search + strlen(search) - 1;
        while (end >= search && *end == ' ') {
            *end = '\0';
            end--;
        }
        int count = 0;
        char *token = strtok(line, ",");
        while (token) {
            // trim token
            while (*token == ' ') token++;
            char *e = token + strlen(token) - 1;
            while (e >= token && *e == ' ') {
                *e = '\0';
                e--;
            }
            if (strcmp(token, search) == 0) ++count;
            token = strtok(NULL, ",");
        }
        printf("The element '%s' appears %d time(s) in the tuple.\n", search, count);
    }
    return 0;
}

