#include <bits/stdc++.h>
using namespace std;

static inline void trim(string &s) {
    size_t start = s.find_first_not_of(' ');
    size_t end = s.find_last_not_of(' ');
    if (start == string::npos) { s.clear(); return; }
    s = s.substr(start, end - start + 1);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    string dummy; getline(cin, dummy); // consume endline after T
    for (int tc = 0; tc < T; ++tc) {
        string line, search;
        getline(cin, line);
        getline(cin, search);
        trim(search);
        int cnt = 0;
        string token;
        stringstream ss(line);
        while (getline(ss, token, ',')) {
            trim(token);
            if (token == search) ++cnt;
        }
        cout << "The element '" << search << "' appears " << cnt << " time(s) in the tuple." << '\n';
    }
    return 0;
}

