import java.io.*;
import java.util.*;

public class Main {
    private static String trim(String s) {
        return s.strip();
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        for (int tc = 0; tc < T; ++tc) {
            String tupleLine = br.readLine();
            String search = br.readLine();
            if (search == null) search = "";
            search = trim(search);
            int cnt = 0;
            if (tupleLine != null && !tupleLine.isEmpty()) {
                String[] parts = tupleLine.split(",");
                for (String part : parts) {
                    String elem = trim(part);
                    if (elem.equals(search)) cnt++;
                }
            }
            System.out.println("The element '" + search + "' appears " + cnt + " time(s) in the tuple.");
        }
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def trim(s: str) -> str:
    return s.strip()

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(T):
        tuple_line = data[idx] if idx < len(data) else ''
        idx += 1
        search = data[idx] if idx < len(data) else ''
        idx += 1
        search = trim(search)
        cnt = 0
        if tuple_line:
            for token in tuple_line.split(','):
                if trim(token) == search:
                    cnt += 1
        out.append(f"The element '{search}' appears {cnt} time(s) in the tuple.")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

